# Before (tightly coupled, untestable):
import anthropic

class ResearchAgent:
    def __init__(self):
        self.client = anthropic.Anthropic()  # hardcoded

    def run(self, query: str) -> str:
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            messages=[{"role": "user", "content": query}],
        )
        return response.content[0].text


# After (dependency-injected, testable):
class ResearchAgent:
    def __init__(self, client: anthropic.Anthropic | None = None):
        self.client = client or anthropic.Anthropic()  # injectable

    def run(self, query: str) -> str:
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=1024,
            messages=[{"role": "user", "content": query}],
        )
        return response.content[0].text

from __future__ import annotations
import anthropic
from collections import deque
from unittest.mock import MagicMock


def make_text_message(text: str) -> anthropic.types.Message:
    """Build a minimal Message object that the agent will parse correctly."""
    content_block = anthropic.types.TextBlock(type="text", text=text)
    return anthropic.types.Message(
        id="msg_test_001",
        type="message",
        role="assistant",
        content=[content_block],
        model="claude-opus-4-5",
        stop_reason="end_turn",
        stop_sequence=None,
        usage=anthropic.types.Usage(input_tokens=10, output_tokens=20),
    )


def make_tool_use_message(tool_name: str, tool_input: dict) -> anthropic.types.Message:
    """Build a Message with a tool_use content block."""
    block = anthropic.types.ToolUseBlock(
        type="tool_use",
        id="toolu_test_001",
        name=tool_name,
        input=tool_input,
    )
    return anthropic.types.Message(
        id="msg_test_002",
        type="message",
        role="assistant",
        content=[block],
        model="claude-opus-4-5",
        stop_reason="tool_use",
        stop_sequence=None,
        usage=anthropic.types.Usage(input_tokens=15, output_tokens=25),
    )


class MockAnthropicClient:
    """A mock Anthropic client that replays scripted responses in order."""

    def __init__(self, responses: list[anthropic.types.Message]):
        self._queue: deque[anthropic.types.Message] = deque(responses)
        self.call_log: list[dict] = []   # records every call for assertion

        # Minimal structure expected by the SDK's attribute access pattern
        self.messages = MagicMock()
        self.messages.create = self._create

    def _create(self, **kwargs) -> anthropic.types.Message:
        self.call_log.append(kwargs)
        if not self._queue:
            raise AssertionError(
                f"MockAnthropicClient: unexpected extra call #{len(self.call_log)} "
                f"— no more scripted responses in queue."
            )
        return self._queue.popleft()

    @property
    def call_count(self) -> int:
        return len(self.call_log)

    def assert_called_n_times(self, n: int) -> None:
        assert self.call_count == n, (
            f"Expected {n} LLM calls, got {self.call_count}"
        )

