@pytest.fixture
def cassette_client(request) -> MockAnthropicClient:
    """Load responses from a cassette JSON file named after the test."""
    cassette_name = request.param  # parametrize with cassette filename
    cassette_path = FIXTURES_DIR / f"{cassette_name}.json"
    data = json.loads(cassette_path.read_text())
    # Reconstruct Message objects from the stored dicts
    responses = [_dict_to_message(r) for r in data["responses"]]
    return MockAnthropicClient(responses=responses)


def _dict_to_message(d: dict) -> anthropic.types.Message:
    # Simplified deserialiser — production code would use pydantic or dataclasses
    import anthropic
    content = []
    for block in d["content"]:
        if block["type"] == "text":
            content.append(anthropic.types.TextBlock(type="text", text=block["text"]))
        elif block["type"] == "tool_use":
            content.append(anthropic.types.ToolUseBlock(
                type="tool_use", id=block["id"],
                name=block["name"], input=block["input"],
            ))
    return anthropic.types.Message(
        id=d["id"], type="message", role="assistant", content=content,
        model=d["model"], stop_reason=d["stop_reason"], stop_sequence=None,
        usage=anthropic.types.Usage(**d["usage"]),
    )

