def test_agent_routes_ticket_to_correct_department(category_client, request):
    from agents.support import SupportAgent
    from tests.mocks import MockToolRegistry

    tools = MockToolRegistry(cassette=request.param)
    agent = SupportAgent(client=category_client, tools=tools)

    # Each cassette encodes a known ticket scenario
    ticket = tools.get_fixture_ticket()
    result = agent.handle(ticket)

    expected_dept = tools.get_expected_department()
    assert result["routed_to"] == expected_dept, (
        f"Ticket '{ticket['subject']}' should route to '{expected_dept}', "
        f"got '{result['routed_to']}'"
    )


