# In conftest.py — filter API keys from VCR cassettes
import pytest

@pytest.fixture(scope="module")
def vcr_config():
    return {
        "filter_headers": ["x-api-key", "authorization", "cookie"],
        "filter_query_parameters": ["api_key", "token"],
        # Replace any remaining key-like strings with a placeholder
        "before_record_response": sanitize_response,
    }

def sanitize_response(response):
    """Strip any key-like values from response bodies before recording."""
    import re
    body = response["body"]["string"]
    if isinstance(body, bytes):
        body = body.decode("utf-8", errors="replace")
    # Replace anything that looks like an Anthropic API key
    body = re.sub(r'sk-ant-[A-Za-z0-9_-]{32,}', 'sk-ant-REDACTED', body)
    response["body"]["string"] = body.encode("utf-8")
    return response
